const statsContainer = document.getElementById('assignment-summary-stats');
if (statsContainer) {
    const total = arr.length;
    const draftCount = arr.filter(item => !item.visible).length;
    const publishedCount = arr.filter(item => item.visible).length;
    const lateCount = arr.filter(item => item.visible && item.openForSubmissions !== false && item.dueAt && new Date(item.dueAt) < new Date()).length;

    statsContainer.innerHTML = `
        <div class="attendance-legend-card" style="background: var(--secondary); border-color: rgba(226,232,240,0.85);">
            <span class="attendance-legend-value" style="color: var(--text-main);">${total}</span>
            <span class="attendance-legend-label">งานทั้งหมด</span>
        </div>
        <div class="attendance-legend-card" style="background: var(--success-bg); border-color: var(--success-border);">
            <span class="attendance-legend-value present" style="color: var(--success-text);">${publishedCount}</span>
            <span class="attendance-legend-label">เผยแพร่</span>
        </div>
        <div class="attendance-legend-card" style="background: var(--secondary); border-color: rgba(226,232,240,0.85);">
            <span class="attendance-legend-value" style="color: var(--text-main);">${draftCount}</span>
            <span class="attendance-legend-label">ยังเป็นร่าง</span>
        </div>
        <div class="attendance-legend-card" style="background: var(--danger-bg); border-color: var(--danger-border);">
            <span class="attendance-legend-value absent" style="color: var(--danger-text);">${lateCount}</span>
            <span class="attendance-legend-label">ส่งงานล่าช้า</span>
        </div>
    `;
}
